from flask import Flask, request, redirect, url_for, session, render_template
import os
import secrets
from pyotp import TOTP

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Mock database of users and their passwords (in real use, store securely)
users = {
    'user1': 'password1',
    'user2': 'password2'
}

# Generate a secret for each user
mfa_secrets = {}
for username in users:
    mfa_secrets[username] = secrets.token_urlsafe(16)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users and users[username] == password:
            session['username'] = username
            return redirect(url_for('verify_mfa'))
        else:
            return 'Invalid credentials', 401
    
    return render_template('login.html')

@app.route('/verify-mfa')
def verify_mfa():
    if 'username' not in session:
        return redirect(url_for('login'))
    
    username = session['username']
    secret = mfa_secrets.get(username)
    
    if not secret:
        return 'MFA setup failed', 500
    
    totp = TOTP(secret)
    if request.args.get('otp'):
        if totp.verify(request.args.get('otp')):
            # MFA verified, allow access
            session['mfa_verified'] = True
            return redirect(url_for('protected_resource'))
        else:
            return 'Invalid OTP', 401
    
    return render_template('verify_mfa.html')

@app.route('/protected')
def protected_resource():
    if 'username' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    
    return f'Welcome, {session["username"]}! Access granted.'

if __name__ == '__main__':
    app.run(debug=True)